);

export const formatter = createFormatter({
  locale: 'en',
  now: new Date(2022, 10, 6, 20, 20, 0, 0)
});

if (process.env.NODE_ENV !== 'production' && !(name in values)) {
  throw new Error(`Missing value for argument "${name}"`);
}

if (process.env.NODE_ENV !== 'production' && !branch) {
  throw new Error(
    `No matching branch for select "${name}" with value "${value}"`
  );
}

if (process.env.NODE_ENV !== 'production' && typeof rawValue !== 'number') {
  throw new Error(
    `Expected number for plural argument "${name}", got ${typeof rawValue}`
  );
}

if (process.env.NODE_ENV !== 'production' && !branch) {
  throw new Error(
    `No matching branch for plural "${name}" with category "${category}"`
  );
}

if (process.env.NODE_ENV !== 'production' && typeof rawValue !== 'number') {
  throw new Error(
    `Expected number for argument "${name}", got ${typeof rawValue}`
  );
}

if (process.env.NODE_ENV !== 'production' && !(rawValue instanceof Date)) {
  throw new Error(
    `Expected Date for argument "${name}", got ${typeof rawValue}`
  );
}

if (typeof style === 'string') {
  const resolved = formatOptions.formats?.dateTime?.[style];
  if (process.env.NODE_ENV !== 'production' && !resolved) {
    throw new Error(`Missing ${type} format "${style}"`);
  }
  return resolved;
}

if (
  process.env.NODE_ENV !== 'production' &&
  typeof rawHandler !== 'function'
) {
  throw new Error(`Expected function for tag handler "${name}"`);
}

const affectedIds = new Set([
  ...(prevFileMessages?.keys() ?? []),
  ...nextFileMessages.keys()
]);

return (
  nextConfig?.turbopack?.rules ||
  // @ts-expect-error -- For Next.js <16
  nextConfig?.experimental?.turbo?.rules ||
  {}
);

const duplicateLocaleMessages = Array.from(domainsByLocale.entries())
    .filter(([, localeDomains]) => localeDomains.size > 1)
    .map(
      ([locale, localeDomains]) =>
        `- "${locale}" is used by: ${Array.from(localeDomains).join(', ')}`
    );

